75: @Path("/connectors")
76: @Produces(MediaType.APPLICATION_JSON)
77: @Consumes(MediaType.APPLICATION_JSON)
78: public class ConnectorsResource {
79:     private static final Logger log = LoggerFactory.getLogger(ConnectorsResource.class);
80: 
81:     private final Herder herder;
82:     private final HerderRequestHandler requestHandler;
83:     @jakarta.ws.rs.core.Context
84:     private ServletContext context;
85:     private final boolean isTopicTrackingDisabled;
86:     private final boolean isTopicTrackingResetDisabled;
87: 
88:     @Inject
89:     public ConnectorsResource(
90:             Herder herder,
91:             RestServerConfig config,
92:             RestClient restClient,
93:             RestRequestTimeout requestTimeout
94:     ) {
95:         this.herder = herder;
96:         this.requestHandler = new HerderRequestHandler(restClient, requestTimeout);
97:         this.isTopicTrackingDisabled = !config.topicTrackingEnabled();
98:         this.isTopicTrackingResetDisabled = !config.topicTrackingResetEnabled();
99:     }
100: 
101:     @GET
102:     @Operation(summary = "List all active connectors")
103:     public Response listConnectors(
104:         final @Context UriInfo uriInfo,
105:         final @Context HttpHeaders headers
106:     ) {
107:         if (uriInfo.getQueryParameters().containsKey("expand")) {
108:             Map<String, Map<String, Object>> out = new HashMap<>();
109:             for (String connector : herder.connectors()) {
110:                 try {
111:                     Map<String, Object> connectorExpansions = new HashMap<>();
112:                     for (String expansion : uriInfo.getQueryParameters().get("expand")) {
113:                         switch (expansion) {
114:                             case "status":
115:                                 connectorExpansions.put("status", herder.connectorStatus(connector));
116:                                 break;
117:                             case "info":
118:                                 connectorExpansions.put("info", herder.connectorInfo(connector));
119:                                 break;
120:                             default:
121:                                 log.info("Ignoring unknown expansion type {}", expansion);
122:                         }
123:                     }
124:                     out.put(connector, connectorExpansions);
125:                 } catch (NotFoundException e) {
126:                     // this likely means that a connector has been removed while we look its info up
127:                     // we can just not include this connector in the return entity
128:                     log.debug("Unable to get connector info for {} on this worker", connector);
129:                 }
130: 
131:             }
132:             return Response.ok(out).build();
133:         } else {
134:             return Response.ok(herder.connectors()).build();
135:         }
136:     }
137: 
138:     @POST
139:     @Operation(summary = "Create a new connector")
140:     public Response createConnector(final @Parameter(hidden = true) @QueryParam("forward") Boolean forward,
141:                                     final @Context HttpHeaders headers,
142:                                     final CreateConnectorRequest createRequest) throws Throwable {
143:         // Trim leading and trailing whitespaces from the connector name, replace null with empty string
144:         // if no name element present to keep validation within validator (NonEmptyStringWithoutControlChars
145:         // allows null values)
146:         String name = createRequest.name() == null ? "" : createRequest.name().trim();
147: 
148:         Map<String, String> configs = createRequest.config();
149:         checkAndPutConnectorConfigName(name, configs);
150: 
151:         FutureCallback<Herder.Created<ConnectorInfo>> cb = new FutureCallback<>();
