32: /**
33:  * Maps uncaught exceptions thrown while handling REST requests to appropriate {@link jakarta.ws.rs.core.Response}s
34:  */
35: public class ConnectExceptionMapper implements ExceptionMapper<Exception> {
36:     private static final Logger log = LoggerFactory.getLogger(ConnectExceptionMapper.class);
37: 
38:     @Context
39:     private UriInfo uriInfo;
40: 
41:     @Override
42:     public Response toResponse(Exception exception) {
43:         log.debug("Uncaught exception in REST call to /{}", uriInfo.getPath(), exception);
44: 
45:         if (exception instanceof ConnectRestException restException) {
46:             return Response.status(restException.statusCode())
47:                     .entity(new ErrorMessage(restException.errorCode(), restException.getMessage()))
48:                     .build();
49:         }
50: 
51:         if (exception instanceof NotFoundException || exception instanceof jakarta.ws.rs.NotFoundException) {
52:             return Response.status(Response.Status.NOT_FOUND)
53:                     .entity(new ErrorMessage(Response.Status.NOT_FOUND.getStatusCode(), exception.getMessage()))
54:                     .build();
55:         }
56: 
57:         if (exception instanceof AlreadyExistsException) {
58:             return Response.status(Response.Status.CONFLICT)
59:                     .entity(new ErrorMessage(Response.Status.CONFLICT.getStatusCode(), exception.getMessage()))
60:                     .build();
61:         }
62: 
63:         if (!log.isDebugEnabled()) {
64:             log.error("Uncaught exception in REST call to /{}", uriInfo.getPath(), exception);
65:         }
66: 
67:         final int statusCode;
68:         if (exception instanceof WebApplicationException) {
69:             Response.StatusType statusInfo = ((WebApplicationException) exception).getResponse().getStatusInfo();
70:             statusCode = statusInfo.getStatusCode();
71:         } else {
72:             statusCode = Response.Status.INTERNAL_SERVER_ERROR.getStatusCode();
73:         }
74:         return Response.status(statusCode)
75:                 .entity(new ErrorMessage(statusCode, exception.getMessage()))
76:                 .build();
77:     }
78: }
